package Lec3;

public class Hello_5times {

	public static void main(String[] args) {
		// TODO Auto-generated method stub

// Program to print hello 5 times using while loop
// In if , else and using loop conditions we dont use ; semi colon
		
int i=1;
while(i<=5)
{
System.out.println("Hello");
i=i+1;
}
	}

}
